// Deduplicate by title+year to remove any duplicates
(function dedup() {
  const seen = new Set();
  const unique = [];
  for (const m of MOVIES_DB) {
    const key = (m.title + m.year).toLowerCase().replace(/\s/g,"");
    if (!seen.has(key)) {
      seen.add(key);
      // Normalize music field (in case of music2 typo)
      if (!m.music) m.music = "Various";
      unique.push(m);
    }
  }
  // Re-assign sequential IDs
  unique.forEach((m, i) => { m.id = i + 1; });
  MOVIES_DB.length = 0;
  unique.forEach(m => MOVIES_DB.push(m));
  console.log(`%c📽️ Tollydle DB loaded: ${MOVIES_DB.length} unique Telugu movies`, "color:#06d6a0;font-size:13px;font-weight:bold");
})();

window.MOVIES_DB = MOVIES_DB;
